You can add a cooldown to prevent users from performing an action too frequently. Here's an example:

### Python Code
```python
import time

class Cooldown:
    def __init__(self, cooldown_time):
        self.cooldown_time = cooldown_time
        self.last_used = 0

    def is_ready(self):
        return time.time() - self.last_used >= self.cooldown_time

    def use(self):
        if self.is_ready():
            self.last_used = time.time()
            return True
        else:
            return False

# Usage
cooldown = Cooldown(10)  # 10 second cooldown

while True:
    if cooldown.use():
        print("Action performed!")
    else:
        print("Cooldown not ready yet. Try again in {:.2f} seconds.".format(cooldown.cooldown_time - (time.time() - cooldown.last_used)))
    time.sleep(1)
```

